import {
  Component,
  Prop,
  State,
  Element,
  Event,
  EventEmitter,
  Method,
  h,
  Host,
  forceUpdate
} from '@stencil/core';
import {
  getHostAttributes,
  getSpreadableAttributes,
  setDefaultHostAttributes,
  setStyleAttribute
} from '@src/utils/kds-utils/attributes/attributeUtils';
import { loadingSpinnerInButtonShouldBeInverse } from '@src/utils/kds-utils/colorUtils';
import { registerAttributeObserver } from '@src/utils/kds-utils/registerObserver';

function hasIconOnly(element) {
  const children = element.children;
  const childNodes = element.childNodes;
  const hasOneIcon = children.length === 1 && isKDSIcon(children[0]);
  const hasText = Array.from(childNodes).some(
    (childNode: any) =>
      childNode.nodeName === '#text' && childNode.textContent.trim().length > 0
  );
  return hasOneIcon && !hasText;
}

function isKDSIcon(child) {
  return child.localName.startsWith('kds-icon');
}

interface HTMLKdsButtonElement extends HTMLButtonElement {
  nativeElement: HTMLElement;
}

const ButtonConversionMap: Record<string, any> = {
  primary: { kind: 'prominent', palette: 'accent', variant: 'fill' },
  'primary-inverse': { kind: 'prominent', palette: 'accent', variant: 'fill', inverse: true },
  secondary: { kind: 'prominent', palette: 'accent', variant: 'border' },
  'secondary-inverse':
    { kind: 'prominent', palette: 'accent', variant: 'border', inverse: true },
  tertiary: { kind: 'prominent', palette: 'accent', variant: 'minimal' },
  'tertiary-inverse':
    { kind: 'prominent', palette: 'accent', variant: 'minimal', inverse: true },
  'primary-positive': { kind: 'prominent', palette: 'positive', variant: 'border' }, // are we sure about the variant on primary-positives?
  'primary-positive-inverse':
    { kind: 'prominent', palette: 'positive', variant: 'border', inverse: true },
  'secondary-positive': { kind: 'prominent', palette: 'positive', variant: 'border' },
  'tertiary-positive': { kind: 'prominent', palette: 'positive', variant: 'minimal' },
  'primary-negative': { kind: 'prominent', palette: 'negative', variant: 'fill' },
  'primary-negative-inverse':
    { kind: 'prominent', palette: 'negative', variant: 'fill', inverse: true },
  'secondary-negative': { kind: 'prominent', palette: 'negative', variant: 'border' },
  'tertiary-negative': { kind: 'prominent', palette: 'negative', variant: 'minimal' },
  cancel: { kind: 'prominent', palette: 'neutral', variant: 'border' },
  favorable: { kind: 'prominent', palette: 'positive', variant: 'fill' },
  'favorable-secondary': { kind: 'prominent', palette: 'positive', variant: 'border' },
  'favorable-tertiary': { kind: 'prominent', palette: 'positive', variant: 'minimal' },
  'favorable-inverse':
    { kind: 'prominent', palette: 'positive', variant: 'fill', inverse: true },
  destructive: { kind: 'prominent', palette: 'negative', variant: 'fill' },
  'destructive-secondary':
    { kind: 'prominent', palette: 'negative', variant: 'border' },
  'destructive-tertiary':
    { kind: 'prominent', palette: 'negative', variant: 'minimal' },
  'destructive-inverse':
    { kind: 'prominent', palette: 'negative', variant: 'fill', inverse: true }
};

/**
 * Buttons make common actions immediately visible and easy to perform with one click or tap.
 *
 * > **Note:** `<kds-button />` is a [primitive web component](primitives/) that accepts all props listed below and any attributes prefixed with `inner-`.
 * `inner-*` attributes are stripped of their `inner-` prefix and placed onto a rendered native `<button>` element.
 */
@Component({
  tag: 'kds-button',
  styleUrl: './themes/kds-button.css',
  shadow: false
})
export class KdsButton {
  @Element() hostEl: HTMLKdsButtonElement;

  /** Applies the compact size. */
  @Prop() readonly compact?: boolean = false;
  /** Sets the color palette. */
  @Prop({ mutable: true }) palette:
    | 'neutral'
    | 'brand'
    | 'accent'
    | 'positive'
    | 'negative'
    | 'informative'
    | 'callout'
    | 'special' = 'brand';

  /** Sets the color kind. */
  @Prop({ mutable: true }) kind: | 'primary'
    | 'primary-inverse'
    | 'secondary'
    | 'secondary-inverse'
    | 'tertiary'
    | 'tertiary-inverse'
    | 'cancel'
    | 'destructive'
    | 'destructive-secondary'
    | 'destructive-tertiary'
    | 'destructive-inverse'
    | 'favorable'
    | 'favorable-secondary'
    | 'favorable-tertiary'
    | 'favorable-inverse' | 'dominant' | 'prominent' | 'subtle' | 'alternate' = 'prominent';
  /** Sets the color variant. */
  @Prop({ mutable: true }) variant: 'fill' | 'border' | 'minimal' = 'fill';
  /** Applies the inverse color styling. */
  @Prop({ mutable: true }) inverse: boolean = false;
  /** Takes focus when the form is presented. */
  @Prop() readonly autofocus: boolean;
  /** Disables if present. */
  @Prop() readonly disabled?: boolean;
  /** Displays a loading spinner as the content of the button if present. */
  @Prop() readonly indeterminate?: boolean;
  /** Associates the field to a form element. */
  @Prop() readonly form?: string;
  /** Overrides the action attribute of the button's form owner. (Submit button type only.) */
  @Prop() readonly formaction?: string;
  /** Specifies the type of content that is used to submit. (Submit button type only.)  */
  @Prop() readonly formenctype?: string;
  /** Specifies the HTTP method used to submit. (Submit button type only.) */
  @Prop() readonly formmethod?: string;
  /** Disables form validation. (Submit button type only.) */
  @Prop() readonly formnovalidate?: boolean;
  /** Indicates where to display response after submission. (Submit button type only.) */
  @Prop() readonly formtarget?: string;
  /** Sets the name. */
  @Prop() readonly name?: string;
  /** Sets the button type. */
  @Prop() readonly type?: string;
  /** Contains the current value. */
  @Prop() readonly value?: string | string[] | number;
  /** Sets a class to the rendered `<button>`. */
  @Prop() readonly buttonClass?: string;

  /** Signifies that a button is in a pressed state when used as a toggle. */
  @Prop() readonly buttonAriaPressed: string | null;
  /** Signifies that a menu has been opened as a result of the user clicking the button. */
  @Prop() readonly buttonAriaExpanded: string | null;
  /** Signifies that a popup has been opened as a result of the user clicking the button. */
  @Prop() readonly buttonAriaHaspopup: string | null;

  @State() innerAttrs: any;

  private iconOnly: Boolean;

  private observer: MutationObserver;

  private buttonElement: HTMLButtonElement;

  /**
   * Emits when the component has been loaded.
   * Event's `detail` contains a reference to the inner button element.
   */
  @Event() ready: EventEmitter<HTMLButtonElement>;

  forceButtonUpdate(): void {
    forceUpdate(this.hostEl);
  }

  private setIconSizes(children: Element[]) {
    children.forEach((child) => {
      isKDSIcon(child) &&
      child.setAttribute('size', this.compact ? 'utility-s' : 'utility-m');
    });
  }

  private setIconClasses(childNodes: NodeListOf<ChildNode>) {
    const children = Array.from(childNodes).filter((node) => {
      if (node.nodeName === '#comment') {
        return false;
      } else if (node.nodeName === '#text' || node.textContent) {
        return node.textContent.trim().length > 0;
      }
      return true;
    });
    children.forEach((childNode, index) => {
      if (!this.iconOnly && childNode.nodeName.startsWith('KDS-ICON')) {
        const icon = childNode as Element;
        !icon.classList.contains('kds-Button-icon') &&
        icon.classList.add('kds-Button-icon');
        index === 0 &&
        !icon.classList.contains('kds-Button-icon--first') &&
        icon.classList.add('kds-Button-icon--first');
        index === children.length - 1 &&
        !icon.classList.contains('kds-Button-icon--last') &&
        icon.classList.add('kds-Button-icon--last');
      }
    });
  }

  componentWillLoad() {
    this.observer = registerAttributeObserver(this);
    this.innerAttrs = getHostAttributes(this.hostEl);
    setDefaultHostAttributes(this.hostEl);

    if (ButtonConversionMap[this.kind]) {
      this.palette = ButtonConversionMap[this.kind].palette;
      this.variant = ButtonConversionMap[this.kind].variant;
      this.inverse = ButtonConversionMap[this.kind].inverse;
      this.kind = ButtonConversionMap[this.kind].kind;
    }
  }

  componentDidLoad() {
    this.observer.observe(this.hostEl, { attributes: true });
    this.ready.emit(this.buttonElement);
    this.hostEl.nativeElement = this.buttonElement;
  }

  disconnectedCallback() {
    this.observer && this.observer.disconnect();
  }

  /**
   * Returns the native `<button>` element used under the hood.
   */
  @Method()
  getNativeElement(): Promise<HTMLButtonElement> {
    return Promise.resolve(this.buttonElement!);
  }

  render() {
    const parentElement = this.buttonElement || this.hostEl;
    this.iconOnly = hasIconOnly(parentElement);
    this.setIconSizes(Array.from(parentElement.children));
    this.setIconClasses(parentElement.childNodes);

    const classes = {
      'kds-Button': true,
      interactive: true,
      [`palette-${this.palette}`]: true,
      [`kind-${ButtonConversionMap[this.kind] ? ButtonConversionMap[this.kind].kind : this.kind}`]: true,
      [`variant-${this.variant}`]: true,
      'kds-Button--compact': this.compact,
      'kds-Button--hasIconOnly': this.iconOnly,
      'is-loading': this.indeterminate,
      'as-inverse': this.inverse,
      [this.buttonClass]: this.buttonClass
    } as { [className: string]: boolean };

    const indeterminateProps = this.indeterminate
      ? {
        role: 'progressbar',
        'aria-valuetext': 'loading'
      }
      : {};

    return (
      <Host style={this.disabled && { 'pointer-events': 'none' }}>
        <button
          aria-pressed={this.buttonAriaPressed}
          aria-expanded={this.buttonAriaExpanded}
          aria-haspopup={this.buttonAriaHaspopup}
          {...getSpreadableAttributes(this.innerAttrs)}
          autoFocus={this.autofocus}
          disabled={this.disabled || this.indeterminate}
          form={this.form}
          formaction={this.formaction}
          formenctype={this.formenctype}
          formmethod={this.formmethod}
          formnovalidate={this.formnovalidate}
          formtarget={this.formtarget}
          name={this.name}
          type={this.type}
          value={this.value}
          class={classes}
          {...indeterminateProps}
          ref={(el: HTMLButtonElement) => {
            this.buttonElement = el;
            setStyleAttribute(el, this.innerAttrs);
          }}
        >
          <slot />
          {this.indeterminate && (
            <kds-loading-spinner
              palette={this.palette}
              inverse={loadingSpinnerInButtonShouldBeInverse({
                buttonInverseState: this.inverse,
                buttonKind: this.kind
              })}
              size='xs'
              label=''
            ></kds-loading-spinner>
          )}
        </button>
      </Host>
    );
  }
}
