import { Component, Prop, h, Host } from '@stencil/core';
import { generateUniqueString } from '@src/utils/kds-utils/generateUniqueString';

@Component({
  tag: "kds-loading-spinner",
  styleUrl: "kds-loading-spinner.css",
  shadow: false
})
export class KdsLoadingSpinner {
  /** Sets the color palette. */
  @Prop() readonly palette:
    | "neutral"
    | "brand"
    | "accent"
    | "positive"
    | "negative"
    | "informative"
    | "callout"
    | "special" = "brand";
  /** Sets a light color scheme for dark backgrounds. */
  @Prop() readonly inverse: boolean;
  /** Indicates what the loading spinner is for. Used for accessibility purposes. */
  @Prop() readonly label: string = "loading";
  /** Controls the dimensions and font-size. */
  @Prop() readonly size: "s" | "m" | "l" | "xs" = "s";

  render() {
    const uniqueLabelID = "label-" + generateUniqueString();
    return (
      <Host class='kds-LoadingSpinner-wrapper'>
        <span
          class={{
            "kds-LoadingSpinner": true,
            [`kds-Text--${this.size}`]: true,
            "kds-LoadingSpinner--preDeprecationFix": true,
            [`palette-${this.palette}`]: true,
            "as-inverse": this.inverse
          }}
        >
          <span role='progressbar' aria-labelledby={uniqueLabelID}>
            <svg
              class={{
                "kds-LoadingSpinner-svg": true,
                [`kds-LoadingSpinner-svg--${this.size}`]: true
              }}
              viewBox='0 0 100 100'
            >
              <circle
                class='kds-LoadingSpinner-svg--ring'
                cx='50'
                cy='50'
                r='48'
                fill='none'
              />
              <circle
                class='kds-LoadingSpinner-svg--dash'
                cx='50'
                cy='50'
                r='48'
                fill='none'
              />
            </svg>
          </span>
          <span
            id={uniqueLabelID}
            class={{
              "kds-LoadingSpinner-label": true,
              "screen-reader": !this.label
            }}
          >
            {this.label || "loading"}
          </span>
        </span>
      </Host>
    );
  }
}
